  1	import * as React from 'react';
  2	import { EmptyBox } from '@odf/shared/generic/status-box';
  3	import { SectionHeading } from '@odf/shared/heading/page-heading';
  4	import { SecretModel, ConfigMapModel } from '@odf/shared/models';
  5	import { getName, getNamespace } from '@odf/shared/selectors';
  6	import { SecretKind, ConfigMapKind, K8sResourceKind } from '@odf/shared/types';
  7	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  8	import { SecretValue } from '@odf/shared/utils/SecretValue';
  9	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 10	import { Base64 } from 'js-base64';
 11	import {
 12	  Button,
 13	  DescriptionList,
 14	  DescriptionListDescription,
 15	  DescriptionListGroup,
 16	  DescriptionListTerm,
 17	} from '@patternfly/react-core';
 18	import { EyeSlashIcon, EyeIcon } from '@patternfly/react-icons';
 19	import '../../style.scss';
 20	
 21	export const GetSecret: React.FC<GetSecretProps> = ({ obj }) => {
 22	  const { t } = useCustomTranslation();
 23	  const [reveal, setReveal] = React.useState(false);
 24	
 25	  const name = getName(obj);
 26	  const namespace = getNamespace(obj);
 27	
 28	  const [secretResource, cmResource] = React.useMemo(
 29	    () => [
 30	      {
 31	        kind: SecretModel.kind,
 32	        namespace,
 33	        name,
 34	        isList: false,
 35	      },
 36	      {
 37	        kind: ConfigMapModel.kind,
 38	        namespace,
 39	        name,
 40	        isList: false,
 41	      },
 42	    ],
 43	    [name, namespace]
 44	  );
 45	
 46	  const [secretData, secretLoaded, secretLoadError] =
 47	    useK8sWatchResource<SecretKind>(secretResource);
 48	
 49	  const [configData, configLoaded, configLoadError] =
 50	    useK8sWatchResource<ConfigMapKind>(cmResource);
 51	  const isLoaded = secretLoaded && configLoaded;
 52	  const error = secretLoadError || configLoadError;
 53	  const bucketName = configData?.data?.BUCKET_NAME;
 54	  const endpoint = `${configData?.data?.BUCKET_HOST}:${configData?.data?.BUCKET_PORT}`;
 55	  const accessKey =
 56	    isLoaded && !error
 57	      ? Base64.decode(secretData?.data?.AWS_ACCESS_KEY_ID)
 58	      : '';
 59	  const secretKey =
 60	    isLoaded && !error
 61	      ? Base64.decode(secretData?.data?.AWS_SECRET_ACCESS_KEY)
 62	      : '';
 63	
 64	  const secretValues =
 65	    isLoaded && !error
 66	      ? [
 67	          { field: 'Endpoint', value: endpoint },
 68	          { field: 'Bucket Name', value: bucketName },
 69	          { field: 'Access Key', value: accessKey },
 70	          { field: 'Secret Key', value: secretKey },
 71	        ]
 72	      : [];
 73	
 74	  const dl = secretValues.length
 75	    ? secretValues.reduce((acc, datum) => {
 76	        const { field, value } = datum;
 77	        acc.push(
 78	          <DescriptionListGroup>
 79	            <DescriptionListTerm key={`${field}-k`} data-test="secret-data">
 80	              {field}
 81	            </DescriptionListTerm>
 82	            <DescriptionListDescription key={`${field}-v`}>
 83	              <SecretValue value={value} reveal={reveal} encoded={false} />
 84	            </DescriptionListDescription>
 85	          </DescriptionListGroup>
 86	        );
 87	
 88	        return acc;
 89	      }, [])
 90	    : [];
 91	
 92	  return dl.length ? (
 93	    <div className="odf-m-pane__body">
 94	      <SectionHeading text={t('Object Bucket Claim Data')}>
 95	        {secretValues.length ? (
 96	          <Button
 97	            type="button"
 98	            onClick={() => setReveal(!reveal)}
 99	            variant="link"
100	            className="pf-m-link--align-right"
101	          >
102	            {reveal ? (
103	              <>
104	                <EyeSlashIcon className="odf-icon-space-r" />
105	                {t('Hide Values')}
106	              </>
107	            ) : (
108	              <>
109	                <EyeIcon className="odf-icon-space-r" />
110	                {t('Reveal Values')}
111	              </>
112	            )}
113	          </Button>
114	        ) : null}
115	      </SectionHeading>
116	      {dl.length ? (
117	        <DescriptionList className="secret-data">{dl}</DescriptionList>
118	      ) : (
119	        <EmptyBox label={t('Data')} />
120	      )}
121	    </div>
122	  ) : null;
123	};
124	
125	type GetSecretProps = {
126	  obj: K8sResourceKind;
127	};

